import{_ as s,C as l,c as i,o as t,j as n,G as p,a2 as r,a as o}from"./chunks/framework.DrNAj9nU.js";const A=JSON.parse('{"title":"AI概念与AI Agent","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/AI概念与AI Agent.md","filePath":"column/AIFuture/基础认知/AI概念与AI Agent.md","lastUpdated":1773825228000}'),d={name:"column/AIFuture/基础认知/AI概念与AI Agent.md"};function c(h,a,u,b,g,m){const e=l("ArticleMetadata");return t(),i("div",null,[a[0]||(a[0]=n("h1",{id:"ai概念与ai-agent",tabindex:"-1"},[o("AI概念与AI Agent "),n("a",{class:"header-anchor",href:"#ai概念与ai-agent","aria-label":'Permalink to "AI概念与AI Agent"'},"​")],-1)),p(e),a[1]||(a[1]=r(`<p>随着人工智能技术的飞速发展，围绕大语言模型（LLM）构建的能力体系正在形成一个多层次、立体化的技术生态。从最基础的模型层，到能力增强层，再到Agent体系、工程化框架，以及最新的推理能力和未来趋势，本文将全景式解析这一技术体系的内在逻辑与核心组件。</p><h2 id="一、模型层-最底层能力" tabindex="-1">一、模型层（最底层能力） <a class="header-anchor" href="#一、模型层-最底层能力" aria-label="Permalink to &quot;一、模型层（最底层能力）&quot;">​</a></h2><p>这是所有上层能力的基础：</p><h3 id="_1-1-llm-大语言模型" tabindex="-1">1.1 LLM（大语言模型） <a class="header-anchor" href="#_1-1-llm-大语言模型" aria-label="Permalink to &quot;1.1 LLM（大语言模型）&quot;">​</a></h3><ul><li>代表：OpenAI、Anthropic</li><li>核心：文本理解 + 生成</li><li>本质：<strong>概率预测下一个 token</strong></li></ul><p>LLM是当前AI浪潮的核心驱动力，代表产品包括<code>OpenAI的GPT系列、Anthropic的Claude</code>系列等。其本质是基于海量文本训练的统计模型，核心机制是概率预测下一个<code>token</code>。</p><p>当我们与<code>ChatGPT</code>对话时，它并不是真正“理解”了语义，而是通过复杂的神经网络计算，不断预测最可能出现的下一个字词。这种机制赋予了模型强大的文本生成和理解能力，使其能够完成写作、翻译、摘要、问答等多种任务。</p><h3 id="_1-2-多模态-multimodal" tabindex="-1">1.2 多模态（Multimodal） <a class="header-anchor" href="#_1-2-多模态-multimodal" aria-label="Permalink to &quot;1.2 多模态（Multimodal）&quot;">​</a></h3><ul><li><p>文本 + 图片 + 音频 + 视频</p></li><li><p>典型能力：</p><ul><li>看图写代码</li><li>语音对话</li><li>视频理解</li></ul></li></ul><p>👉 趋势：从“会说话” → “会看 + 会听 + 会操作”</p><p>多模态能力是模型从“会说话”向“会看、会听、会操作”进化的必然趋势。它整合了文本、图片、音频、视频等多种数据形态，形成了更全面的感知能力。</p><p>典型应用包括：上传一张产品截图让AI生成对应代码、直接与AI进行语音对话交流、让AI理解视频内容并进行摘要等。多模态模型正在打破不同信息形态之间的壁垒，使AI更接近人类的感知方式。</p><h2 id="二、能力增强层-让模型更-聪明" tabindex="-1">二、能力增强层（让模型更“聪明”） <a class="header-anchor" href="#二、能力增强层-让模型更-聪明" aria-label="Permalink to &quot;二、能力增强层（让模型更“聪明”）&quot;">​</a></h2><h3 id="_2-1-rag-retrieval-augmented-generation" tabindex="-1">2.1 RAG（Retrieval-Augmented Generation） <a class="header-anchor" href="#_2-1-rag-retrieval-augmented-generation" aria-label="Permalink to &quot;2.1 RAG（Retrieval-Augmented Generation）&quot;">​</a></h3><p>RAG的核心思想是模型+外部知识库的组合模式。当用户提出问题时，系统首先从外部知识库中检索相关信息，然后将这些信息作为上下文拼接，最后交给LLM生成回答。</p><ul><li><p>中文：检索增强生成</p></li><li><p>核心思想：</p><blockquote><p><strong>模型 + 外部知识库</strong></p></blockquote></li></ul><p>👉 这种架构有效解决了两个关键问题：</p><ul><li><strong>幻觉问题（胡编）</strong>：基于检索到的真实信息生成，大幅降低胡编乱造的概率</li><li><strong>数据更新问题</strong>：外部知识库可随时更新，无需重新训练模型</li></ul><p>📌 典型结构：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户问题 → 向量检索 → 拼接上下文 → LLM回答</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-2-embedding-向量化" tabindex="-1">2.2 Embedding（向量化） <a class="header-anchor" href="#_2-2-embedding-向量化" aria-label="Permalink to &quot;2.2 Embedding（向量化）&quot;">​</a></h3><p><code>Embedding</code> 是将文本、图片等非结构化数据转化为数值向量的技术。这些向量在数学空间中的位置和距离，代表了原始内容的语义相似度。</p><ul><li><p>把文本变成向量</p></li><li><p>用于：</p><ul><li>相似度搜索</li><li>语义匹配</li></ul></li></ul><p>👉 是 RAG 的基础设施</p><h3 id="_2-3-向量数据库-vector-db" tabindex="-1">2.3 向量数据库（Vector DB） <a class="header-anchor" href="#_2-3-向量数据库-vector-db" aria-label="Permalink to &quot;2.3 向量数据库（Vector DB）&quot;">​</a></h3><p>与传统数据库不同，向量数据库支持高效的相似性搜索，能够快速找到与查询向量最相似的记录，是实现RAG架构的关键组件。</p><p>常见：</p><ul><li>Pinecone</li><li>Weaviate</li><li>Milvus</li></ul><p>👉 用来存 embedding</p><h2 id="三、agent-体系-从被动应答到主动执行" tabindex="-1">三、Agent 体系（从被动应答到主动执行） <a class="header-anchor" href="#三、agent-体系-从被动应答到主动执行" aria-label="Permalink to &quot;三、Agent 体系（从被动应答到主动执行）&quot;">​</a></h2><h3 id="_3-1-agent-智能体" tabindex="-1">3.1 Agent（智能体） <a class="header-anchor" href="#_3-1-agent-智能体" aria-label="Permalink to &quot;3.1 Agent（智能体）&quot;">​</a></h3><p>核心：</p><blockquote><p><strong>LLM + 工具 + 记忆 + 规划能力</strong></p></blockquote><p>能力：</p><ul><li>自动拆解复杂任务为可执行的子任务</li><li>根据需要调用外部工具（如搜索引擎、计算器、API接口）</li><li>在连续多轮交互中保持状态和执行轨迹</li></ul><h3 id="_3-2-mcp-model-context-protocol" tabindex="-1">3.2 MCP（Model Context Protocol） <a class="header-anchor" href="#_3-2-mcp-model-context-protocol" aria-label="Permalink to &quot;3.2 MCP（Model Context Protocol）&quot;">​</a></h3><p><code>MCP</code>是标准化模型调用工具的协议。它解决了过去Agent开发中“每个工具都要单独适配”的问题，通过统一接口规范，大幅降低了Agent与工具集成的成本。 简单来说，MCP就像USB-C接口，让模型可以“即插即用”各种工具，而不是为每个设备准备专门的充电线。</p><p>👉 本质：</p><blockquote><p><strong>给模型“标准化接工具”的协议</strong></p></blockquote><p>作用：</p><ul><li>统一工具调用方式</li><li>降低 Agent 集成成本</li></ul><h3 id="_3-3-agents-md" tabindex="-1">3.3 agents.md <a class="header-anchor" href="#_3-3-agents-md" aria-label="Permalink to &quot;3.3 agents.md&quot;">​</a></h3><p><code>agents.md</code>文件可以理解为给Agent的“说明书”，是system prompt的结构化版本。它明确规定了Agent的角色定位、行为准则、可用工具、限制条件等信息，让Agent的行为更加可控和可预期。</p><p>👉 本质：</p><blockquote><p><strong>给 Agent 的“说明书”</strong></p></blockquote><p>类似：</p><ul><li>system prompt 的结构化版本</li></ul><h3 id="_3-4-agent-skills-技能体系" tabindex="-1">3.4 Agent Skills（技能体系） <a class="header-anchor" href="#_3-4-agent-skills-技能体系" aria-label="Permalink to &quot;3.4 Agent Skills（技能体系）&quot;">​</a></h3><p>技能体系是可复用的能力模块集合。例如，查天气是一个技能，查数据库是另一个技能，调用外部API也是一个技能。将这些基础技能模块化，可以在不同Agent之间共享复用，提高开发效率。</p><p>👉 本质：</p><blockquote><p><strong>可复用的能力模块</strong></p></blockquote><p>比如：</p><ul><li>查天气</li><li>查数据库</li><li>调接口</li></ul><h2 id="四、编排-框架层-工程化" tabindex="-1">四、编排 &amp; 框架层（工程化） <a class="header-anchor" href="#四、编排-框架层-工程化" aria-label="Permalink to &quot;四、编排 &amp; 框架层（工程化）&quot;">​</a></h2><h3 id="_4-1-agent-framework-agent框架" tabindex="-1">4.1 Agent Framework（Agent框架） <a class="header-anchor" href="#_4-1-agent-framework-agent框架" aria-label="Permalink to &quot;4.1 Agent Framework（Agent框架）&quot;">​</a></h3><p>常见：</p><ul><li>LangChain</li><li>LlamaIndex</li></ul><p>作用：</p><ul><li>工具调用的管理和路由</li><li>多轮对话的记忆维护</li><li>任务执行流程的编排与外部系统的集成</li></ul><h3 id="_4-2-workflow-dag-工作流" tabindex="-1">4.2 Workflow / DAG（工作流） <a class="header-anchor" href="#_4-2-workflow-dag-工作流" aria-label="Permalink to &quot;4.2 Workflow / DAG（工作流）&quot;">​</a></h3><p>👉 把 AI 任务拆成流程：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入</span></span>
<span class="line"><span> → 检索</span></span>
<span class="line"><span> → 推理</span></span>
<span class="line"><span> → 调工具</span></span>
<span class="line"><span> → 输出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>典型形态：</p><ul><li>类似后端微服务编排</li></ul><h3 id="_4-3-function-calling-函数调用" tabindex="-1">4.3 Function Calling（函数调用） <a class="header-anchor" href="#_4-3-function-calling-函数调用" aria-label="Permalink to &quot;4.3 Function Calling（函数调用）&quot;">​</a></h3><p>👉 LLM 可以直接输出：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;get_weather&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;city&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Shanghai&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>系统接收到这个指令后，解析并执行对应的函数，将结果返回给模型继续处理。这是Agent能够“行动”的技术基础。</p><p>👉 是 Agent 能执行的关键</p><h2 id="五、记忆体系-越来越火" tabindex="-1">五、记忆体系（越来越火） <a class="header-anchor" href="#五、记忆体系-越来越火" aria-label="Permalink to &quot;五、记忆体系（越来越火）&quot;">​</a></h2><h3 id="_5-1-memory-记忆" tabindex="-1">5.1 Memory（记忆） <a class="header-anchor" href="#_5-1-memory-记忆" aria-label="Permalink to &quot;5.1 Memory（记忆）&quot;">​</a></h3><p>分三种：</p><ul><li>短期记忆（上下文）：当前对话窗口内的上下文，用于维持连贯对话</li><li>长期记忆（数据库）：跨会话存储的向量化信息，让AI能记住历史交互</li><li>用户记忆（个性化）：针对特定用户的个性化信息，如偏好、习惯、历史行为</li></ul><p>越来越多的产品正在探索“AI有记忆”的能力，让每次交互都建立在过往的基础上，而非从零开始。</p><h2 id="六、推理能力-2024–2026爆火" tabindex="-1">六、推理能力（2024–2026爆火） <a class="header-anchor" href="#六、推理能力-2024–2026爆火" aria-label="Permalink to &quot;六、推理能力（2024–2026爆火）&quot;">​</a></h2><h3 id="_6-1-reasoning-推理模型" tabindex="-1">6.1 Reasoning（推理模型） <a class="header-anchor" href="#_6-1-reasoning-推理模型" aria-label="Permalink to &quot;6.1 Reasoning（推理模型）&quot;">​</a></h3><p>代表趋势：</p><ul><li>chain-of-thought</li><li>多步推理</li></ul><p>👉 模型不只是“回答”，而是“思考”</p><h3 id="_6-2-react-reason-act" tabindex="-1">6.2 ReAct（Reason + Act） <a class="header-anchor" href="#_6-2-react-reason-act" aria-label="Permalink to &quot;6.2 ReAct（Reason + Act）&quot;">​</a></h3><p>思考 + 行动结合：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Thought（思考下一步） → Action（执行行动） → Observation（观察结果） → Thought（继续思考）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 Agent 核心模式</p><h2 id="七、自动化-ai工程" tabindex="-1">七、自动化 &amp; AI工程 <a class="header-anchor" href="#七、自动化-ai工程" aria-label="Permalink to &quot;七、自动化 &amp; AI工程&quot;">​</a></h2><h3 id="_7-1-autogpt-babyagi" tabindex="-1">7.1 AutoGPT / BabyAGI <a class="header-anchor" href="#_7-1-autogpt-babyagi" aria-label="Permalink to &quot;7.1 AutoGPT / BabyAGI&quot;">​</a></h3><p>👉 自动完成任务的早期形态</p><p>特点：</p><ul><li>自己拆任务</li><li>自己执行</li></ul><h3 id="_7-2-ai-coding-agent" tabindex="-1">7.2 AI Coding Agent <a class="header-anchor" href="#_7-2-ai-coding-agent" aria-label="Permalink to &quot;7.2 AI Coding Agent&quot;">​</a></h3><p>代表趋势：</p><ul><li>AI 写代码 + 改代码 + 跑代码</li><li>已经在改变开发模式</li></ul><h2 id="总结一张认知图" tabindex="-1">总结一张认知图 <a class="header-anchor" href="#总结一张认知图" aria-label="Permalink to &quot;总结一张认知图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型层</span></span>
<span class="line"><span>  └── LLM / 多模态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>能力增强</span></span>
<span class="line"><span>  └── RAG / Embedding / 向量数据库</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent层</span></span>
<span class="line"><span>  └── Agent / MCP / Skills / agents.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工程层</span></span>
<span class="line"><span>  └── LangChain / Workflow / Function Calling</span></span>
<span class="line"><span></span></span>
<span class="line"><span>智能增强</span></span>
<span class="line"><span>  └── Memory / Reasoning / ReAct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>未来趋势</span></span>
<span class="line"><span>  └── Multi-Agent / AI Native / Tool Use</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div>`,93))])}const q=s(d,[["render",c]]);export{A as __pageData,q as default};
